package ru.memearena.meme.api; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.web.bind.annotation.*; import ru.memearena.meme.application.MemeService; import ru.memearena.meme.domain.ModerationStatus; import ru.memearena.user.infrastructure.UserProfileRepository; import java.util.*; @RestController @RequestMapping("/api/v1/local") public class LocalMemeModerationController { private final MemeService service; private final UserProfileRepository users; public LocalMemeModerationController(MemeService service,UserProfileRepository users){this.service=service;this.users=users;} @GetMapping("/moderation/memes") public ModerationQueueResponse queue(@RequestParam(defaultValue="PENDING") ModerationStatus status,@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(100) int size){var p=service.moderationQueue(status,page,size); var items=p.getContent().stream().map(m->ModerationMemeItemResponse.of(m,users.findById(m.getUploaderId()).map(u->u.getNickname()).orElse(null))).toList(); return new ModerationQueueResponse(items,page,size,p.getTotalElements(),p.getTotalPages());} @PostMapping("/moderation/memes/{memeId}/approve") public MemeResponse approve(@PathVariable UUID memeId){return MemeResponse.from(service.approve(memeId));} @PostMapping("/moderation/memes/{memeId}/reject") public MemeResponse reject(@PathVariable UUID memeId,@Valid @RequestBody RejectMemeRequest r){return MemeResponse.from(service.reject(memeId,r.reason()));} @Deprecated @PostMapping("/memes/{memeId}/approve") public MemeResponse oldApprove(@PathVariable UUID memeId){return approve(memeId);} @Deprecated @PostMapping("/memes/{memeId}/reject") public MemeResponse oldReject(@PathVariable UUID memeId){return MemeResponse.from(service.reject(memeId,"Rejected locally"));} }
